from fractions import Fraction
def gcd(a, b):
    return b if a == 0 else gcd(b%a, a)

points = [map(int, raw_input().split()) for i in xrange(8)]
slope = []
for i in xrange(8):
    for j in xrange(i+1, 8):
        if points[i][0] == points[j][0]:
            slope.append(Fraction(1, 0))
        elif points[i][1] == points[j][1]:
            slope.append(Fraction(0, 1))
        else:
            slope.append(Fraction(points[i][1]-points[j][1], points[i][0]-points[j][0]))
slope.sort()

for i in xrange(6):
    if slope[i] == slope[i+1]:
        print "ugly"
        exit(0)

